#!/usr/bin/env python3
"""批量扩充史部+医部+复本"""
import re, os, sys

wd = 'tmp'

# ===== 史部 =====

# shi-1 史记 28节
with open(f'{wd}/shi1.txt', 'w') as f:
    lines = []
    data = [
        ('五帝本纪', '黄帝者，少典之子，姓公孙，名曰轩辕。生而神灵，弱而能言，幼而徇齐，长而敦敏，成而聪明。轩辕之时，神农氏世衰。诸侯相侵伐，暴虐百姓，而神农氏弗能征。于是轩辕乃习用干戈，以征不享，诸侯咸来宾从。而蚩尤最为暴，莫能伐。炎帝欲侵陵诸侯，诸侯咸归轩辕。轩辕乃修德振兵，治五气，艺五种，抚万民，度四方。教熊罴貔貅貙虎，以与炎帝战于阪泉之野。三战，然后得其志。蚩尤作乱，不用帝命。于是黄帝乃征师诸侯，与蚩尤战于涿鹿之野，遂禽杀蚩尤。而诸侯咸尊轩辕为天子，代神农氏，是为黄帝。', '黄帝战炎帝擒蚩尤代神农为天子是中华民族的人文始祖。'),
        ('项羽本纪', '项籍者，下相人也，字羽。初起时，年二十四。其季父项梁。项氏世世为楚将，封于项，故姓项氏。项羽乃悉引兵渡河，皆沉船，破釜甑，烧庐舍，持三日粮，以示士卒必死，无一还心。于是至则围王离，与秦军遇，九战，绝其甬道，大破之。杀苏角，虏王离。涉间不降楚，自烧杀。当是时，楚兵冠诸侯。诸侯军救钜鹿下者十余壁，莫敢纵兵。及楚击秦，诸将皆从壁上观。楚战士无不一以当十，楚兵呼声动天，诸侯军无不人人惴恐。', '项羽破釜沉舟大破秦军巨鹿之战威震诸侯是灭秦第一功臣。'),
        ('高祖本纪', '高祖，沛丰邑中阳里人，姓刘氏，字季。父曰太公，母曰刘媪。其先刘媪尝息大泽之陂，梦与神遇。是时雷电晦冥，太公往视，则见蛟龙于其上。已而有身，遂产高祖。高祖为人，隆准而龙颜，美须髯，左股有七十二黑子。仁而爱人，喜施，意豁如也。常有大度，不事家人生产作业。高祖常繇咸阳，纵观，观秦皇帝，喟然太息曰：嗟乎，大丈夫当如此也！', '刘邦见秦始皇感叹大丈夫当如此胸怀大志从布衣到帝王的传奇。'),
        ('吕后本纪', '吕太后者，高祖微时妃也，生孝惠帝、女鲁元太后。及高祖为汉王，得定陶戚姬，爱幸，生赵隐王如意。孝惠为人仁弱，高祖以为不类我，常欲废太子，立戚姬子如意。吕后年长，常留守，希见上，益疏。如意立为赵王后，几代太子者数矣，赖大臣争之，及留侯策，太子得毋废。吕后最怨戚夫人及其子赵王，乃令永巷囚戚夫人，而召赵王诛之。太后遂断戚夫人手足，去眼，熏耳，饮瘖药，使居厕中，命曰人彘。', '吕后残忍害戚夫人和赵王如意反映宫廷斗争的残酷也是她掌权的开端。'),
        ('孔子世家', '孔子生鲁昌平乡陬邑。先宋人也。其生而首上圩顶，故因名曰丘云。字仲尼，姓孔氏。孔子长九尺有六寸，人皆谓之长人而异之。孔子语鲁大师：乐其可知也。始作翕如，纵之纯如，皦如绎如也，以成。孔子适周问礼，盖见老子云。辞去而老子送之曰：吾闻富贵者送人以财，仁人者送人以言。吾不能富贵，窃仁人之号，送子以言。孔子自周反于鲁，弟子稍益进焉。', '孔子适周问礼于老子老子送以仁人之言的教诲令人深思。'),
        ('陈涉世家', '陈胜者，阳城人也，字涉。吴广者，阳夏人也，字叔。陈涉少时，尝与人佣耕，辍耕之垄上，怅恨久之，曰：苟富贵，无相忘。佣者笑而应曰：若为佣耕，何富贵也？陈涉太息曰：嗟乎，燕雀安知鸿鹄之志哉！二世元年七月，发闾左适戍渔阳，九百人屯大泽乡。会天大雨，道不通，度已失期。失期，法皆斩。陈胜吴广乃谋曰：今亡亦死，举大计亦死，等死，死国可乎？', '王侯将相宁有种乎燕雀安知鸿鹄之志陈涉首倡反秦揭开了亡秦序幕。'),
        ('伯夷列传', '夫学者载籍极博，犹考信于六艺。诗书虽缺，然虞夏之文可知也。尧将逊位，让于虞舜。舜禹之间，岳牧咸荐，乃试之于位，典职数十年，功用既兴，然后授政。示天下重器，王者大统，传天下若斯之难也。而说者曰尧让天下于许由，许由不受，耻之逃隐。及夏之时，有卞随务光者。此何以称焉？伯夷叔齐，孤竹君之二子也。父欲立叔齐，及父卒，叔齐让伯夷。伯夷曰：父命也。遂逃去。', '伯夷叔齐让国饿死首阳山孔子称其求仁得仁是列传第一的深意。'),
        ('管晏列传', '管仲夷吾者，颍上人也。少时常与鲍叔牙游，鲍叔知其贤。管仲贫困，常欺鲍叔，鲍叔终善遇之，不以为言。已而鲍叔事齐公子小白，管仲事公子纠。及小白立为桓公，公子纠死，管仲囚焉。鲍叔遂进管仲于桓公。管仲既用，任政于齐，齐桓公以霸，九合诸侯，一匡天下，管仲之谋也。管仲曰：吾始困时，尝与鲍叔贾，分财利多自与，鲍叔不以我为贪，知我贫也。吾尝为鲍叔谋事而更穷困，鲍叔不以我为愚，知时有利不利也。吾尝三仕三见逐于君，鲍叔不以我为不肖，知我不遭时也。', '管鲍之交的深厚情谊鲍叔牙知贤荐贤成就了齐桓公一匡天下的霸业。'),
        ('孙子吴起列传', '孙子武者，齐人也。以兵法见于吴王阖庐。阖庐曰：子之十三篇，吾尽观之矣，可以小试勒兵乎？对曰：可。阖庐曰：可试以妇人乎？曰：可。于是许之，出宫中美人，得百八十人。孙子分为二队，以王之宠姬二人各为队长。约束既布，乃设鈇钺，即三令五申之。于是鼓之右，妇人大笑。孙子曰：约束不明，申令不熟，将之罪也。复三令五申而鼓之左，妇人复大笑。孙子曰：既已明而不如法者，吏士之罪也。乃欲斩左右队长。', '孙武练女兵斩宠姬将在军君命有所不受的军事原则淋漓尽致。'),
        ('伍子胥列传', '伍子胥者，楚人也，名员。员父曰伍奢，兄曰伍尚。其先曰伍举，以直谏事楚庄王，有显。楚平王有太子名曰建，使伍奢为太傅，费无忌为少傅。无忌不忠于太子建。平王使无忌为太子取妇于秦，秦女好，无忌驰归报平王曰：秦女绝美，王可自取，而更为太子取妇。平王遂自取秦女而绝爱幸之。伍奢曰：王独奈何以谗贼小臣疏骨肉之亲乎？平王怒，杀伍奢伍尚。伍子胥走至昭关，昭关欲执之。追者在后，几不得脱。至江，江上有一渔父乘船，知伍胥之急，乃渡伍胥。', '伍子胥过昭关一夜白头父兄被害的深仇大恨终引吴兵破楚鞭尸。'),
        ('商君列传', '商君者，卫之诸庶孽公子也，名鞅，姓公孙氏。鞅少好刑名之学，事魏相公叔痤为中庶子。公叔痤知其贤，未及进。会痤病，魏惠王亲往问病。公叔曰：痤之中庶子公孙鞅，年虽少，有奇才，愿王举国而听之。王默然。王且去，痤屏人言曰：王即不听用鞅，必杀之，无令出境。王许诺而去。鞅闻之，曰：彼王不能用君之言任臣，又安能用君之言杀臣乎？卒不去。', '商鞅闻魏王不能用君之言任臣安能用君之言杀臣不去的机智。'),
        ('苏秦列传', '苏秦者，东周洛阳人也。东事师于齐，而习之于鬼谷先生。出游数岁，大困而归。兄弟嫂妹妻妾窃皆笑之，曰：周人之俗，治产业，力工商，逐什二以为务。今子释本而事口舌，困，不亦宜乎！苏秦闻之而惭，自伤，乃闭室不出，出其书遍观之。得周书阴符，伏而读之。期年，以出揣摩，曰：此可以说当世之君矣。苏秦为从约长，并相六国。北报赵王，乃行过洛阳，车骑辎重，诸侯各发使送之甚众，拟于王者。', '苏秦刺股读书终佩六国相印富贵而归的传奇激励了无数后人。'),
        ('张仪列传', '张仪者，魏人也。始尝与苏秦俱事鬼谷先生，学术。苏秦自以不及张仪。张仪已学而游说诸侯。尝从楚相饮，已而楚相亡璧，门下意张仪，曰：仪贫无行，必此盗相君之璧。共执张仪，掠笞数百，不服，释之。其妻曰：嘻！子毋读书游说，安得此辱乎？张仪谓其妻曰：视吾舌尚在不？其妻笑曰：舌在也。仪曰：足矣。', '张仪被诬盗璧受笞问视吾舌尚在不舌在足矣的自信后来凭三寸不烂之舌连横破纵。'),
        ('孟尝君列传', '孟尝君名文，姓田氏。其父婴，齐威王少子。文以父功，封于薛。孟尝君在薛，招致诸侯宾客及亡人有罪者，皆归孟尝君。孟尝君舍业厚遇之，以故倾天下之士。食客数千人，无贵贱一与文等。曾侍客夜食，有一人蔽火光。客怒，以饭不等，辍食辞去。孟尝君起，自持其饭比之。客惭，自刭。士以此多归孟尝君。', '孟尝君好客养士三千食客鸡鸣狗盗之徒各有所用不拘一格用人才。'),
        ('平原君列传', '平原君赵胜者，赵之诸公子也。诸子中胜最贤，喜宾客，宾客盖至者数千人。平原君家楼临民家。民家有躄者，盘散行汲。平原君美人居楼上，临见，大笑之。明日，躄者至平原君门，请曰：臣闻君之喜士，士不远千里而至者，以君能贵士而贱妾也。臣不幸有罢癃之病，而君之后宫临而笑臣，臣愿得笑臣者头。平原君笑应曰：诺。躄者去，平原君笑曰：观此竖子，乃欲以一笑之故杀吾美人，不亦甚乎！终不杀。居岁余，宾客门下舍人稍稍引去者过半。平原君怪之。门下一人曰：以君之不杀笑躄者。', '平原君为留住贤士最终斩杀笑躄者的美人贵士而贱色值得深思。'),
        ('信陵君列传', '魏公子无忌者，魏昭王少子而魏安釐王异母弟也。昭王薨，安釐王即位，封公子为信陵君。公子为人仁而下士，士无贤不肖皆谦而礼交之，不敢以其富贵骄士。士以此方数千里争往归之，致食客三千人。当是时，诸侯以公子贤，多客，不敢加兵谋魏十余年。魏有隐士曰侯嬴，年七十，家贫，为大梁夷门监者。公子闻之，往请，欲厚遗之。不肯受。公子于是乃置酒大会宾客。坐定，公子从车骑，虚左，自迎夷门侯生。侯生摄敝衣冠，直上载公子上坐，不让，欲以观公子。公子执辔愈恭。', '信陵君礼贤下士亲迎侯嬴为战国四公子之首窃符救赵名垂千古。'),
        ('廉颇蔺相如列传', '廉颇者，赵之良将也。赵惠文王十六年，廉颇为赵将伐齐，大破之，取阳晋，拜为上卿，以勇气闻于诸侯。蔺相如者，赵人也，为赵宦者令缪贤舍人。赵王得楚和氏璧，秦昭王闻之，使人遗赵王书，愿以十五城请易璧。臣舍人蔺相如可使。于是王召见，问蔺相如。相如曰：王必无人，臣愿奉璧往使。城入赵而璧留秦，城不入，臣请完璧归赵。赵王于是遂遣相如奉璧西入秦。相如视秦王无意偿赵城，乃前曰：璧有瑕，请指示王。王授璧，相如因持璧却立，倚柱，怒发上冲冠。', '完璧归赵将相和负荆请罪廉颇蔺相如的故事是爱国忍让的典范。'),
        ('屈原贾生列传', '屈原者，名平，楚之同姓也。为楚怀王左徒。博闻强志，明于治乱，娴于辞令。入则与王图议国事，以出号令。出则接遇宾客，应对诸侯。王甚任之。上官大夫与之同列，争宠而心害其能。怀王使屈原造为宪令，屈平属草稿未定。上官大夫见而欲夺之，屈平不与，因谗之曰：王使屈平为令，众莫不知，每一令出，平伐其功，以为非我莫能为也。王怒而疏屈平。屈平疾王听之不聪也，谗谄之蔽明也，邪曲之害公也，方正之不容也，故忧愁幽思而作离骚。', '屈原被谗遭疏忧愁幽思而作离骚上下求索的精神千古传颂。'),
        ('刺客列传', '荆轲者，卫人也。其先乃齐人，徙于卫，卫人谓之庆卿。而之燕，燕人谓之荆卿。荆卿好读书击剑，以术说卫元君，卫元君不用。荆轲嗜酒，日与狗屠及高渐离饮于燕市。酒酣以往，高渐离击筑，荆轲和而歌于市中，相乐也。已而相泣，旁若无人者。荆轲遂入秦，持千金之资币物，厚遗秦王宠臣中庶子蒙嘉。嘉为先言于秦王。秦王闻之，大喜，乃朝服，设九宾，见燕使者咸阳宫。荆轲奉樊於期头函，而秦舞阳奉地图柙，以次进。至陛，秦舞阳色变振恐。荆轲顾笑舞阳，前谢曰：北蕃蛮夷之鄙人，未尝见天子，故振慑。', '荆轲刺秦王风萧萧兮易水寒壮士一去兮不复还是最悲壮的刺客史诗。'),
        ('淮阴侯列传', '淮阴侯韩信者，淮阴人也。始为布衣时，贫无行，不得推择为吏，又不能治生商贾，常从人寄食饮，人多厌之者。常数从其下乡南昌亭长寄食，数月，亭长妻患之，乃晨炊蓐食。食时信往，不为具食。信亦知其意，怒，竟绝去。信钓于城下，诸母漂，有一母见信饥，饭信，竟漂数十日。信喜，谓漂母曰：吾必有以重报母。信至国，召所从食漂母，赐千金。及下乡南昌亭长，赐百钱，曰：公，小人也，为德不卒。', '韩信千金报漂母一饭之恩从胯下之辱到封坛拜将一生极具传奇色彩。'),
        ('李将军列传', '李将军广者，陇西成纪人也。其先曰李信，秦时为将。广世世受射。孝文帝十四年，匈奴大入萧关，而广以良家子从军击胡，用善骑射，杀首虏多，为汉中郎。广居右北平，匈奴闻之，号曰汉之飞将军，避之数岁，不敢入右北平。广出猎，见草中石，以为虎而射之，中石没镞，视之石也。因复更射之，终不能复入石矣。广廉，得赏赐辄分其麾下，饮食与士共之。终广之身，为二千石四十余年，家无余财，终不言家产事。', '李广射石没镞飞将军之号匈奴不敢犯但终生未得封侯。'),
        ('卫将军骠骑列传', '大将军卫青者，平阳人也。其父郑季，为吏，给事平阳侯家，与侯妾卫媪通，生青。青壮，为侯家骑，从平阳主。建元二年春，青姊子夫得入宫幸上。青为太中大夫。元光五年，青为车骑将军，击匈奴，出上谷，斩首虏数百。其后匈奴入杀辽西太守，败韩将军。青复出云中以西至高阙，遂略河南地，至于陇西，捕首虏数千，畜数十百万。天子曰：青功，益封青三千户。', '卫青从骑奴到大将军七击匈奴收复河朔河套地区是汉代最耀眼的军事天才。'),
        ('司马相如列传', '司马相如者，蜀郡成都人也，字长卿。少时好读书，学击剑。其亲名之曰犬子。相如既学，慕蔺相如之为人，更名相如。会梁孝王卒，相如归，而家贫，无以自业。素与临邛令王吉相善。临邛中多富人，而卓王孙家僮八百人。程郑亦数百人。二人乃相谓曰：令有贵客，为具召之。并召令。令既至，卓氏客以百数。至日中，谒司马长卿，长卿谢病不能往。临邛令不敢尝食，身自迎相如。相如为不得已而强往，一坐尽倾。酒酣，令前奏琴曰：窃闻长卿好之，愿以自娱。相如辞谢，为鼓一再行。是时卓王孙有女文君新寡，好音，故相如缪与令相重，而以琴心挑之。相如之临邛，从车骑，雍容闲雅甚都。及饮卓氏，弄琴，文君窃从户窥之，心悦而好之。', '司马相如琴挑卓文君私奔当垆卖酒是中国文学史上最浪漫的爱情故事。'),
        ('货殖列传', '太史公曰：夫神农以前，吾不知已。至若诗书所述，虞夏以来，耳目欲极声色之好，口欲穷刍豢之味，身安逸乐，而心夸矜势能之荣。使俗之渐民久矣，虽户说以眇论，终不能化。故善者因之，其次利道之，其次教诲之，其次整齐之，最下者与之争。夫山西饶材竹榖纑旄玉石，山东多鱼盐漆丝声色。江南出楠梓姜桂金锡连丹沙犀玳瑁珠玑齿革。龙门碣石北多马牛羊旃裘筋角。铜铁则千里往往山出釭置。此其大较也。', '天下熙熙皆为利来天下攘攘皆为利往货殖列传为商人正名体现了司马迁超越时代的经济思想。'),
        ('太史公自序', '太史公曰：先人有言，自周公卒五百岁而有孔子。孔子卒后至于今五百岁，有能绍明世，正易传，继春秋，本诗书礼乐之际。意在斯乎！意在斯乎！小子何敢让焉。上大夫壶遂曰：昔孔子何为而作春秋哉？太史公曰：余闻董生曰：周道衰废，孔子为鲁司寇，诸侯害之，大夫壅之。孔子知言之不用，道之不行也，是非二百四十二年之中，以为天下仪表，贬天子，退诸侯，讨大夫，以达王事而已矣。', '司马迁继孔子作春秋而作史记小子何敢让焉的担当成就了史家之绝唱无韵之离骚。'),
        ('报任安书', '太史公牛马走司马迁再拜言。少卿足下：曩者辱赐书，教以慎于接物，推贤进士为务。意气勤勤恳恳。若望仆不相师，而用流俗人之言。仆非敢如此也。仆闻之：修身者，智之符也。爱施者，仁之端也。取予者，义之表也。耻辱者，勇之决也。立名者，行之极也。士有此五者，然后可以托于世，而列于君子之林矣。人固有一死，或重于泰山，或轻于鸿毛，用之所趋异也。', '人固有一死或重于泰山或轻于鸿毛司马迁忍辱负重完成史记的伟大精神。'),
        ('史记总论', '史记者，司马迁之所作也。起于黄帝，迄于汉武帝，凡百三十篇。本纪十二，表十，书八，世家三十，列传七十。网罗天下放失旧闻，考之行事，稽其成败兴坏之理。亦欲以究天人之际，通古今之变，成一家之言。其文雄深雅健，其情跌宕悲慨。鲁迅称之为史家之绝唱无韵之离骚。诚哉斯言。', '究天人之际通古今之变成一家之言是史记的写作宗旨也是司马迁最伟大的贡献。'),
    ]
    for i, (title, orig, trans) in enumerate(data, 1):
        lines.append(f'''      {{
        id: 'shi-1-s{i}',
        title: '{title}',
        original: '{orig}',
        translation: '{trans}',
        interpretation: '',
      }},''')
    f.write('\n'.join(lines))

print(f"shi1: {len(data)}节")
